import open3d as o3d
import json
from pypcd4 import PointCloud
import numpy as np

OUT_DIR = "output"

def write_in_pcd(points, idx):
    fields = ("x", "y", "z", "intensity", "vx", "vy", "time")
    types = (np.float32, np.float32, np.float32, np.float32, np.float32, np.float32, np.float32)

    # Save to file
    pc = PointCloud.from_points(points, fields=fields, types=types)
    idx = str(idx).zfill(6)
    pc.save(f"{OUT_DIR}/lidar/{idx}.pcd")


