def write_labels(predictions, class_names, idx):
    # Write the labels to a text file
    frame_data = []

    pred_boxes = predictions['pred_boxes'].cpu().numpy()
    pred_scores = predictions['pred_scores'].cpu().numpy()
    pred_labels = predictions['pred_labels'].cpu().numpy()
    idx = str(idx).zfill(6)
    with open(f"{OUT_DIR}/label/{idx}.json", "w") as f:
        for i in range(len(pred_scores)):
            cx = float(pred_boxes[i][0])
            cy = float(pred_boxes[i][1])
            cz = float(pred_boxes[i][2])
            dx = float(pred_boxes[i][3]) / 2.0  # half-length (x)
            dy = float(pred_boxes[i][4]) / 2.0  # half-width (y)
            dz = float(pred_boxes[i][5]) / 2.0  # half-height (z)

            class_name = str(class_names[pred_labels[i]-1]) if 0 < pred_labels[i] <= len(class_names) else "unknown"
            if class_name == "unknown":
                print(f"-------- WARNINGGGG: pred label = {pred_labels[i]}")

            if pred_scores[i] > 0.3:  
                data = {"psr": {
                    "position": {
                        "x": float(pred_boxes[i][0]),
                        "y": float(pred_boxes[i][1]),
                        "z": float(pred_boxes[i][2])
                    },
                    "scale": {
                        "x": float(pred_boxes[i][3]),
                        "y": float(pred_boxes[i][4]),
                        "z": float(pred_boxes[i][5])
                    },
                    "rotation": {
                        "x": 0.0,
                        "y": 0.0,
                        "z": float(pred_boxes[i][6])
                    },
                    "obj_type": class_name,
                    "obj_id": str(i),
                    "vertices": [
                        # 1. Front-Left-Bottom (+x, +y, -z)
                        cx + dx, cy + dy, cz - dz, 1.0,
                        # 2. Front-Right-Bottom (+x, -y, -z)
                        cx + dx, cy - dy, cz - dz, 1.0,
                        # 3. Front-Right-Top (+x, -y, +z)
                        cx + dx, cy - dy, cz + dz, 1.0,
                        # 4. Front-Left-Top (+x, +y, +z)
                        cx + dx, cy + dy, cz + dz, 1.0,
                        
                        # 5. Rear-Left-Bottom (-x, +y, -z)
                        cx - dx, cy + dy, cz - dz, 1.0,
                        # 6. Rear-Right-Bottom (-x, -y, -z)
                        cx - dx, cy - dy, cz - dz, 1.0,
                        # 7. Rear-Right-Top (-x, -y, +z)
                        cx - dx, cy - dy, cz + dz, 1.0,
                        # 8. Rear-Left-Top (-x, +y, +z)
                        cx - dx, cy + dy, cz + dz, 1.0
                    ] 
                }}
                frame_data.append(data)

        json.dump(frame_data, f, ensure_ascii=False, indent=4)